var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"착륙까지 에스코트해줘서 고맙군.","JPN":"着陸までのエスコートに感謝する。","ENG":"Thank you for escorting us to our landing.","TWN":"感謝你護送我們著陸。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"저희는 임무를 이행했을 뿐입니다.","JPN":"私たちは任務を遂行したまでです。","ENG":"We were merely doing our job.","TWN":"我們只是按照任務行事。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"관리국이 기술 협조를 위해 올 것이란 공문은 전해받았습니다.","JPN":"管理局が技術協力のために来るということは公文書で伝達されていました。","ENG":"We received an official letter saying that the Administration would arrive for technical cooperation.","TWN":"不久前，我們收到文書說管理局將會派人前來進行技術協助。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이미 알고 있었다니 당황스러운걸.","JPN":"すでに知っていたとは、驚いたな。","ENG":"I'm surprised you already knew.","TWN":"真讓人吃驚，你說你們早就知道了？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"폐 끼치지 않으려고 일부러 조용히 움직였는데, 정보기관이 제법 유능한가보군.","JPN":"迷惑をかけないように静かに行動したのだが、なかなか有能な情報機関を持っているようだ。","ENG":"We deliberately moved quietly to not cause any trouble, but it seems you have a competent intelligence agency.","TWN":"為了不引起麻煩，我們特意低調行動，看來你們的情報機構還蠻有能耐的嘛。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"상부 오라클의 지시는 틀린 적이 없으니까요.","JPN":"上層部オラクルの指示が間違ったことはありませんから。","ENG":"Orders from the Oracle are never wrong.","TWN":"神諭的指示從未出錯。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오라클이라… 아직도 그 프로젝트의 생존자가 남아있었나?","JPN":"オラクルか……まだそのプロジェクトの生き残りがいたのかね？","ENG":"Oracle... Are there still survivors of that project?","TWN":"神諭計畫嗎……那個計畫竟然還有倖存者？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"저희는 사령부 지시에 따를 뿐, 정보를 제공해드릴 순 없습니다.","JPN":"私たちは司令部の指示に従うだけで、情報を提供することはできません。","ENG":"We only follow orders from the Command. We cannot provide you with information.","TWN":"我們只遵從司令部的指示，無法給你提供更多資訊。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SCIENTIST_UNION_NPC_NULL","text":{"KOREA":"원하는 목적지로 무사히 모셔드리는 것까지가 저희의 임무입니다.","JPN":"お望みの目的地まで無事送り届けることが私たちの任務です。","ENG":"Our mission was to get you safely to your destination.","TWN":"我們的任務是安全地將你送到目的地。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SCIENTIST_UNION_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"라고 말하면서 저 사람들… 총구를 내려놓을 생각이 없어 보이는데요?","JPN":"とか言いながらあの人たち……銃を下ろす気はなさそうなんですけど。","ENG":"They say that, but... their guns are still aimed at us.","TWN":"話雖這麼說……但那些人看起來沒有放下槍的打算啊……？"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크흠.","JPN":"コホン。","ENG":"Ahem.","TWN":"咳嗯。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"굳이 성의를 거절해가며 저들을 곤란하게 만들 필요는 없겠지.","JPN":"厚意を拒絶してまであの人たちを困らせる必要はないだろう。","ENG":"There is no need to cause trouble for them by refusing their generosity.","TWN":"也沒有必要拒絕他們的好意，讓他們為難。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"괜찮다면 그라운드 제로까지 안내를 부탁하네.","JPN":"よかったらグラウンド・ゼロまで案内を頼む。","ENG":"Could you guide us to Ground Zero, then?","TWN":"如果可以的話，請帶我去G0。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이게 어떻게 된 상황이죠?","JPN":"これ、どういう状況なんですか？","ENG":"What's going on?","TWN":"這是怎麼回事……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_CAR_SHAKE"},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"관리국이 온다는 걸 북방합의체에 알린 적이 있었나요?","JPN":"管理局が来ることを北方合意体に知らせたことがあるんでしたっけ？","ENG":"Did someone inform the Northern Union that the Administration was coming?","TWN":"我們有通知過北方和議會嗎……？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"금시초문입니다.","JPN":"初耳です。","ENG":"That is news to me.","TWN":"我竟然對此一無所知。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"심지어 외부 접근을 가장 꺼려하는 1급 보안구역으로 직접 안내해주다니. 지나치게 친절하군요.","JPN":"しかももっとも外部からの接近を嫌う1級保安区域に直接案内してくれるとは。親切すぎますね。","ENG":"They are even escorting us to a level 1 security area that they do not want outsiders accessing. Their hospitality appears excessive.","TWN":"還親自帶我們前往最忌諱外人進入的一級保安區。真是過於熱情了呢。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"어쩌면 그들도 불필요한 마찰을 피하고 싶은 걸지도 모르지.","JPN":"もしかしたら彼らも不要なもめごとを避けたいのかもしれない。","ENG":"Perhaps they also want to avoid any unnecessary conflict.","TWN":"或許他們也想避免不必要的摩擦吧。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"섣불리 적대하기보단 호의를 받아들이는 편이 지금으로선 최선인 것 같군.","JPN":"今は下手に敵対するより厚意を受け入れた方がベストのようだ。","ENG":"The best course of action right now is to accept their hospitality rather than assuming hostility.","TWN":"與其草率交惡，不如接受善意，現在看來這是最好的選擇。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"상부의 지시라면… 펠릭스의 입김이 닿았을 가능성이 높겠죠.","JPN":"上層部の指示なら……フェリックスの息がかかった可能性が高いでしょう。","ENG":"If it's an order from the top... it's highly likely that Felix has something to do with it.","TWN":"如果是上面的指示……很可能是緋莉克絲的意思。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"대체 무슨 꿍꿍이일까요?","JPN":"いったい何を企んでいるんでしょうか？","ENG":"What are they scheming?","TWN":"他們到底在打什麼主意？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 목적은 북방합의체에서 실종된 두 인물을 찾아내는 걸세.","JPN":"私たちの目的は北方合意体で失踪した2人を探すことだ。","ENG":"Our objective is to find the two people who went missing in the Northern Union.","TWN":"我們的目的是在北方和議會中找到失蹤的那兩個人。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 의도를 알고 있다면 자신들이 실종과 무관함을 증명하고 싶은 걸지도 모르지.","JPN":"その意図をわかっているなら、自分たちが失踪とは関係がないということを証明したいのかもしれない。","ENG":"If they know about our intentions, they might be hoping to prove that they had nothing to do with their disappearance.","TWN":"如果他們知道了我們的意圖，恐怕只是想證明自己與此次失蹤事件無關。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저희가 오는 경로를 예측한 것도 모자라 여기에 온 이유까지 알고 있다고요?","JPN":"私たちが来る経路を予測してさらに、ここに来た理由までわかってるんですか？","ENG":"So, not only did they predict our route, but they also know why we're here?","TWN":"所以……他們不僅預測到了我們的路線，還知道我們來這裡的原因？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"독심술사도 그런 건 못할 것 같은데.","JPN":"読心術師でもそれはできないと思うんですけど。","ENG":"I don't think even a psychic could figure that out.","TWN":"就算是讀心術也做不到這樣吧……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L39_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"독심술로는 어렵겠지만, 미래를 내다봤다면 가능한 일이지.","JPN":"読心術では難しいと思うが、未来を見たなら可能なことさ。","ENG":"Perhaps not by reading minds, but it is possible if they predict the future.","TWN":"讀心術可能很難，但如果能預知未來的話，那就有可能了。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하하… 전제가 좀 이상하지 않나요? 예언 같은 게 실제로 가능할 리가…","JPN":"はは……前提がちょっとおかしくないですか？　予言なんか、実際にできるわけ……","ENG":"Haha... Doesn't that premise sound odd? There's no way prophecies are real...","TWN":"哈、哈……那就更奇怪了吧？預見未來什麼的怎麼可能是真的呢……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"…진심이세요?","JPN":"……本気ですか？","ENG":"...Are you being serious?","TWN":"……你們是認真的嗎？"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"오라클 프로젝트. 북방합의체가 연구하던 기술 중 하나죠.","JPN":"オラクルプロジェクト。北方合意体が研究していた技術の1つです。","ENG":"The Oracle project. It's one of the technologies the Northern Union was researching.","TWN":"神諭計畫。是北方和議會研究的技術之一。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"보고서에 따르면 유일한 성공사례와 핵심연구진은 이미 사망한 것으로 확인됐습니다만…","JPN":"報告書によりますと、唯一の成功例と中心核の研究陣はすでに死亡したと確認されましたが……","ENG":"According to reports, the one successful case and its core researchers were confirmed to be dead...","TWN":"之前報告顯示，唯一的成功案例和核心研究人員已經確認死亡……"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리가 모르는 실험체가 더 남았던 모양이군.","JPN":"私たちの知らない実験体がまだ残っていたようだな。","ENG":"But it seems that there are test subjects we didn't know about.","TWN":"看來還有我們不知道的實驗品啊。"},"stage":{"bg":"VEHICLE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}}]`);export{e as default};